<?php/DevelopmentErrorReportingif(!defined('DEVELOPMENT_MODE')){error_reporting(E_ALL);ini_set('display_errors',1);ini_set('display_startup_errors',1);}declare(strict_types=1);/***NRPFormatValidatorFixer*UpdateNRPvalidationtoacceptbothNRP(8-9digit)andNIP(18digit)formats*/require_once__DIR__.'/../core/config.php';require_once__DIR__.'/../core/Database.php';require_once__DIR__.'/APIResponse.php';classNRPValidationFixer{private$pdo;publicfunction__construct(){$db=Database::getInstance();$this->pdo=$db->getConnection();}/***UpdateNRPvalidationlogicinallrelevantfiles*/publicfunctionfixNRPValidation(){$results=[];try{/UpdateDataQualityAnalyzer$results[]=$this->updateDataQualityAnalyzer();/Verifythefix$results[]=$this->verifyNRPValidation();return['success'=>true,'message'=>'NRPvalidationupdatedtoacceptNRPandNIPformats','results'=>$results,'timestamp'=>date('c')];}catch(Exception$e){return['success'=>false,'message'=>'ErrorupdatingNRPvalidation:'.$e->getMessage(),'timestamp'=>date('c')];}}/***UpdateDataQualityAnalyzerNRPvalidation*/privatefunctionupdateDataQualityAnalyzer(){$file_path=__DIR__.'/DataQualityAnalyzer.php';/Readcurrentfile$content=file_get_contents($file_path);/UpdateNRPvalidationregextoacceptbothNRP(8-9digits)andNIP(18digits)$old_pattern="nrpNOTREGEXP'^\[0-9\]\{8,9\}\$'";$new_pattern="nrpNOTREGEXP'^\[0-9\]\{8,9\}\$'ANDnrpNOTREGEXP'^\[0-9\]\{18\}\$'";$content=str_replace($old_pattern,$new_pattern,$content);/Alsoupdatethevalidationlogicdescription$old_desc="Found3personilwithinvalidNRPformat";$new_desc="FoundpersonilwithinvalidNRP/NIPformat";$content=str_replace($old_desc,$new_desc,$content);/Writeupdatedfilefile_put_contents($file_path,$content);return['file'=>'DataQualityAnalyzer.php','action'=>'updated','message'=>'UpdatedNRPvalidationtoaccept8-9digitNRPand18digitNIPformats'];}/***VerifyNRPvalidationafterfix*/publicfunctionverifyNRPValidation(){/Testthenewvalidationlogic$sql="SELECTCOUNT(*)astotal,COUNT(CASEWHENnrpREGEXP'^[0-9]{8,9}$'ORnrpREGEXP'^[0-9]{18}$'THEN1END)asvalid,COUNT(CASEWHENnrpISnullORnrp=''THEN1END)asempty,COUNT(CASEWHENnrpNOTREGEXP'^[0-9]{8,9}$'ANDnrpNOTREGEXP'^[0-9]{18}$'ANDnrpISNOTnullANDnrp!=''THEN1END)asinvalidFROMpersonilWHEREis_deleted=0";$stmt=$this->pdo->query($sql);$stats=$stmt->fetch(PDO::FETCH_ASSOC);/Getsamplerecords$sample_sql="SELECTid,nama,nrp,CASEWHENnrpREGEXP'^[0-9]{8,9}$'THEN'NRP'WHENnrpREGEXP'^[0-9]{18}$'THEN'NIP'WHENnrpISnullORnrp=''THEN'empty'ELSE'invalid'ENDasformat_typeFROMpersonilWHEREis_deleted=0ORDERBYidLIMIT10";$stmt=$this->pdo->query($sample_sql);$samples=$stmt->fetchAll(PDO::FETCH_ASSOC);return['validation_stats'=>$stats,'sample_records'=>$samples,'all_valid'=>$stats['invalid']==0,'message'=>"NRPvalidationnowacceptsbothformats:{$stats['valid']}valid,{$stats['invalid']}invalid"];}/***Re-rundataqualityanalysiswithupdatedvalidation*/publicfunctionrerunQualityAnalysis(){/IncludeandruntheupdatedDataQualityAnalyzerrequire_once__DIR__.'/DataQualityAnalyzer.php';$analyzer=newDataQualityAnalyzer();$result=$analyzer->analyzeQuality();return['quality_score'=>$result['summary']['overall_quality_score'],'format_issues'=>$result['metrics']['personil']['format_issues']??[],'message'=>'QualityanalysiscompletedwithupdatedNRPvalidation'];}}/Executeifaccesseddirectlyif(basename($_SERVER['PHP_SELF'])===basename(__FILE__)){header('Content-Type:application/json');try{$fixer=newNRPValidationFixer();/FixNRPvalidation$fix_result=$fixer->fixNRPValidation();/Verifythefix$verify_result=$fixer->verifyNRPValidation();/Re-runqualityanalysis$quality_result=$fixer->rerunQualityAnalysis();echojson_encode(APIResponse::success(['fix_result'=>$fix_result,'verification'=>$verify_result,'quality_analysis'=>$quality_result],'NRPvalidationfixcompleted'));}catch(Exception$e){echojson_encode(APIResponse::error($e->getMessage(),500));}}?>
